// All JSON — no binary access needed here
const openaiKey = $('Extract Metadata').first().json.openaiKey;
const meta = $('Extract Metadata').first().json;

// fileId comes from the previous HTTP Request node (Upload File to OpenAI)
const uploadResult = $input.first().json;
const fileId = uploadResult.id;
if (!openaiKey) throw new Error("Missing OPENAI_API_KEY — check n8n env vars");
if (!fileId) throw new Error("No fileId from upload step: " + JSON.stringify(uploadResult));

const headers = {
  "Authorization": `Bearer ${openaiKey}`,
  "OpenAI-Beta": "assistants=v2",
  "Content-Type": "application/json"
};

const prompt = `You are a master data extractor. Extract ALL product rows from this price list.
Output ONLY a valid JSON object (no markdown, no fences):
{"rows": [{"name":"...","article":"...","qty":1,"purchase_price":100,"volume_l":0.75,"country":"...","category":"...","note":"..."}]}
If a field value is unknown use null.`;

// 1. Create assistant
const aResp = await fetch("https://api.openai.com/v1/assistants", {
  method: "POST", headers,
  body: JSON.stringify({
    name: "BahusExtractorTemp",
    model: "gpt-4o",
    instructions: prompt,
    tools: [{ type: "file_search" }],
    tool_resources: { file_search: { vector_stores: [{ file_ids: [fileId] }] } }
  })
});
if (!aResp.ok) throw new Error("Create assistant failed: " + await aResp.text());
const assistantId = (await aResp.json()).id;
let threadId, runId;

try {
  // 2. Create thread + run in one call
  const runResp = await fetch("https://api.openai.com/v1/threads/runs", {
    method: "POST", headers,
    body: JSON.stringify({
      assistant_id: assistantId,
      thread: { messages: [{ role: "user", content: "Extract all product rows. Return ONLY JSON." }] },
      response_format: { type: "json_object" }
    })
  });
  if (!runResp.ok) throw new Error("Create run failed: " + await runResp.text());
  const runRes = await runResp.json();
  threadId = runRes.thread_id;
  runId = runRes.id;

  // 3. Poll (max 90 × 3s = ~4.5 min)
  let status = runRes.status;
  let attempts = 0;
  while ((status === "queued" || status === "in_progress") && attempts < 90) {
    await new Promise(r => setTimeout(r, 3000));
    attempts++;
    const p = await fetch(`https://api.openai.com/v1/threads/${threadId}/runs/${runId}`, { headers });
    const pj = await p.json();
    status = pj.status;
    if (["failed","cancelled","expired"].includes(status))
      throw new Error(`Run ${status}: ${JSON.stringify(pj.last_error || {})}`);
  }
  if (status !== "completed") throw new Error(`Timed out after ${attempts} polls, status=${status}`);

  // 4. Get assistant reply
  const msgResp = await fetch(`https://api.openai.com/v1/threads/${threadId}/messages`, { headers });
  const msgs = await msgResp.json();
  const block = msgs.data?.[0]?.content?.find(c => c.type === "text");
  const rawText = block ? block.text.value : '{"rows":[]}';

  // 5. Cleanup (fire & forget)
  fetch(`https://api.openai.com/v1/assistants/${assistantId}`, { method: "DELETE", headers }).catch(() => {});
  fetch(`https://api.openai.com/v1/files/${fileId}`, { method: "DELETE", headers: { Authorization: `Bearer ${openaiKey}` } }).catch(() => {});

  // 6. Parse + return for downstream Format Success node
  let rows = [];
  try {
    const parsed = JSON.parse(rawText);
    rows = Array.isArray(parsed) ? parsed : (parsed.rows || []);
  } catch(e) {
    throw new Error("Failed to parse AI response as JSON: " + rawText.slice(0, 200));
  }

  return { json: { choices: [{ message: { content: JSON.stringify({ rows }) } }] } };

} catch(e) {
  // Cleanup on any error
  if (assistantId) fetch(`https://api.openai.com/v1/assistants/${assistantId}`, { method: "DELETE", headers }).catch(() => {});
  if (fileId) fetch(`https://api.openai.com/v1/files/${fileId}`, { method: "DELETE", headers: { Authorization: `Bearer ${openaiKey}` } }).catch(() => {});
  throw e;
}

const meta = $('Extract Metadata').first().json;
let extractedRows = [];
let errorMessage = null;
try {
  let rawText = $input.first().json.choices[0].message.content;
  if (rawText.includes("```")) rawText = rawText.replace(/```json?/g,"").replace(/```/g,"").trim();
  const parsed = JSON.parse(rawText);
  extractedRows = Array.isArray(parsed) ? parsed : (parsed.rows || []);
} catch(e) {
  errorMessage = "Parse error: " + e.message;
}
if (!errorMessage && extractedRows.length === 0) errorMessage = "No rows extracted from document";
if (errorMessage) {
  return { json: { import_batch_id: meta.importId, job_id: meta.jobId, status: "failed", error: errorMessage, callbackFailedUrl: meta.callbackFailedUrl } };
}
return { json: { import_batch_id: meta.importId, job_id: meta.jobId, status: "parsed", rows: extractedRows, callbackSuccessUrl: meta.callbackSuccessUrl } };

const meta = $('Extract Metadata').first().json;
return { json: {
  import_batch_id: meta.importId, job_id: meta.jobId,
  status: "failed",
  error: "Unsupported format: " + $json.filename + ". Only PDF files are accepted.",
  callbackFailedUrl: meta.callbackFailedUrl
}};
